#include <iostream>
#include <string>
using namespace std;

int main()
{
    int age = 25;
    double price = 19.99;
    string name = "Ahmet";
    bool isActive = true;
    char grade = 'A';

    cout << "Isim: " << name << endl;
    cout << "Yas: " << age << endl;
    cout << "Fiyat: " << price << endl;
    cout << "Aktif mi: " << isActive << endl;
    cout << "Not: " << grade << endl;

    // Tip donusumu
    string ageText = to_string(age);
    int parsedAge = stoi("30");
    double parsedPrice = stod("9.5");

    cout << "\nYas metni: " << ageText << endl;
    cout << "Donusturulen yas: " << parsedAge << endl;
    cout << "Donusturulen fiyat: " << parsedPrice << endl;

    // auto ile otomatik tip cikarimi
    auto city = string("Istanbul");
    cout << "\nSehir: " << city << endl;

    // const kullanimi
    const double PI = 3.14159;
    cout << "Pi sayisi: " << PI << endl;

    return 0;
}
